import hashlib

def hash_fichier(chemin, algorithme="sha256"):
    """Calcule le hash d'un fichier de façon efficace (par blocs)."""
    h = hashlib.new(algorithme)
    try:
        with open(chemin, "rb") as f:  # Mode binaire obligatoire
            # Lecture par blocs de 64KB pour les gros fichiers
            for bloc in iter(lambda: f.read(65536), b""):
                h.update(bloc)
        return h.hexdigest()
    except FileNotFoundError:
        return None
    except PermissionError:
        return "PERMISSION_DENIED"

# Calculer plusieurs hashs en même temps
def hashs_fichier(chemin):
    """Retourne MD5, SHA1 et SHA256 d'un fichier."""
    algos = {"md5": hashlib.md5(), "sha1": hashlib.sha1(), "sha256": hashlib.sha256()}
    try:
        with open(chemin, "rb") as f:
            for bloc in iter(lambda: f.read(65536), b""):
                for h in algos.values():
                    h.update(bloc)
        return {nom: h.hexdigest() for nom, h in algos.items()}
    except Exception as e:
        return {"error": str(e)}

# Test sur un fichier système
result = hashs_fichier(r"C:\Windows\System32\drivers\etc\hosts")
for algo, val in result.items():
    print(f"{algo.upper()}: {val}")
