import hashlib
import json
import os
from datetime import datetime

def creer_baseline(dossier, extensions=[".exe", ".dll", ".sys"]):
    """Crée une baseline des hashs des fichiers critiques."""
    baseline = {
        "created_at": datetime.now().isoformat(),
        "dossier": dossier,
        "fichiers": {}
    }

    try:
        for racine, _, fichiers in os.walk(dossier):
            for nom in fichiers:
                if any(nom.lower().endswith(ext) for ext in extensions):
                    chemin = os.path.join(racine, nom)
                    h = hash_fichier(chemin)
                    if h and h != "PERMISSION_DENIED":
                        baseline["fichiers"][chemin] = {
                            "sha256": h,
                            "taille": os.path.getsize(chemin)
                        }
    except Exception as e:
        print(f"Erreur: {e}")

    return baseline

def comparer_baseline(baseline_avant, baseline_apres):
    """Compare deux baselines et retourne les modifications."""
    resultats = {"modifies": [], "ajoutes": [], "supprimes": []}

    avant = baseline_avant["fichiers"]
    apres = baseline_apres["fichiers"]

    for chemin, infos in avant.items():
        if chemin not in apres:
            resultats["supprimes"].append(chemin)
        elif infos["sha256"] != apres[chemin]["sha256"]:
            resultats["modifies"].append(chemin)

    resultats["ajoutes"] = [c for c in apres if c not in avant]
    return resultats
